<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html,body{background:transparent;width:100%;font-family:'Inter',sans-serif;-webkit-tap-highlight-color:transparent}
:root{
  --bg:#080d17;--card:#0d1320;--sec:#121a2c;--sec2:#16203a;--bd:#222d44;--bd2:#33415f;
  --t1:#eaf2fb;--t2:#9fb0cc;--t3:#67769a;
  --aq:#4fd6e6;--aq-hi:#8be8f3;--aq-dim:#2f8d9c;--aq-bg:rgba(79,214,230,0.10);--aq-line:rgba(79,214,230,0.30);
  --gold:#e2b341;--gold-bg:rgba(226,179,65,0.12);--gold-line:rgba(226,179,65,0.32);
  --red:#e0625a;--grn:#5fc27e;
  --fh:'Cinzel',serif;--ft:'Spectral',serif;
}
.app.lt{
  --bg:#dde6f2;--card:#ffffff;--sec:#eef3fa;--sec2:#e3ebf6;--bd:#cdd9ea;--bd2:#b3c4dc;
  --t1:#13203a;--t2:#4a5a78;--t3:#7587a6;
  --aq:#1c92a8;--aq-hi:#34b0c6;--aq-dim:#2f8d9c;--aq-bg:rgba(28,146,168,0.10);--aq-line:rgba(28,146,168,0.30);
  --gold:#b3851d;--gold-bg:rgba(179,133,29,0.12);--gold-line:rgba(179,133,29,0.30);
}
svg{display:block}
.app{max-width:520px;margin:8px auto;background:var(--card);border:1px solid var(--bd2);border-radius:12px;overflow:hidden;box-shadow:0 18px 52px rgba(0,0,0,0.55);position:relative}
.app::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,var(--aq-dim),var(--aq),var(--aq-dim),transparent);z-index:6}
.top{padding:20px 20px 14px;background:linear-gradient(180deg,var(--sec2),var(--card));border-bottom:1px solid var(--bd);position:relative}
.top-meta{display:flex;justify-content:space-between;font-family:var(--fh);font-size:9px;color:var(--t3);letter-spacing:2px;text-transform:uppercase;margin-bottom:10px}
.toolbar{position:absolute;right:14px;top:32px;display:flex;gap:6px}
.tbtn{font-family:var(--fh);font-size:9px;letter-spacing:1px;color:var(--t2);background:var(--card);border:1px solid var(--bd2);border-radius:5px;padding:4px 8px;cursor:pointer}
.tbtn:hover{color:var(--aq);border-color:var(--aq-dim)}
.top h1{font-family:'Cinzel Decorative','Cinzel',serif;font-size:20px;font-weight:900;color:var(--t1);letter-spacing:1px;text-align:center;margin-top:4px}
.top .sub{font-family:var(--ft);font-size:11px;font-style:italic;color:var(--t2);text-align:center;margin-top:4px}
.tabs{display:flex;gap:4px;padding:11px 12px;background:var(--sec);overflow-x:auto;scrollbar-width:none;border-bottom:1px solid var(--bd)}
.tabs::-webkit-scrollbar{display:none}
.tab{flex:1 0 auto;white-space:nowrap;display:flex;align-items:center;gap:6px;padding:8px 11px;cursor:pointer;color:var(--t2);background:var(--card);border:1px solid var(--bd);border-radius:6px;font-family:var(--fh);font-size:9px;font-weight:600;letter-spacing:0.5px;text-transform:uppercase}
.tab svg{width:13px;height:13px;stroke:currentColor;fill:none;stroke-width:1.7}
.tab.on{color:var(--bg);background:linear-gradient(180deg,var(--aq-hi),var(--aq));border-color:var(--aq)}
.page{display:none;padding:18px 20px}.page.on{display:block;animation:f .25s ease}
@keyframes f{from{opacity:0;transform:translateY(3px)}to{opacity:1;transform:none}}
.rec{font-family:var(--fh);font-size:11px;font-weight:600;color:var(--aq);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:4px}
.rec-d{font-family:var(--ft);font-size:11px;font-style:italic;color:var(--t3);margin-bottom:16px;line-height:1.5}
.fld{margin-bottom:15px}
.lbl{display:block;font-family:var(--fh);font-size:9px;font-weight:600;color:var(--t2);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:6px}
.hint{font-family:var(--ft);font-size:10px;font-style:italic;color:var(--t3);margin-top:5px;line-height:1.45}
input[type=text],input[type=number],textarea,select{width:100%;background:var(--sec);border:1px solid var(--bd2);border-radius:6px;color:var(--t1);font-family:var(--ft);font-size:13px;padding:9px 11px;outline:none}
input:focus,textarea:focus,select:focus{border-color:var(--aq-dim);box-shadow:0 0 0 2px var(--aq-bg)}
textarea{resize:vertical;min-height:64px;line-height:1.5}
select{cursor:pointer}
.row{display:flex;gap:10px}.row>*{flex:1}
.cusrow{display:flex;gap:8px;align-items:flex-start}.cusrow>div:first-child{flex:1;min-width:0}
.cusbtn{flex-shrink:0;font-family:var(--fh);font-size:8.5px;letter-spacing:1px;color:var(--aq);background:var(--aq-bg);border:1px solid var(--aq-dim);border-radius:6px;padding:9px 8px;cursor:pointer;white-space:nowrap}
.cusbtn:hover{background:var(--aq);color:var(--bg)}
/* level */
.lvbox{background:var(--sec);border:1px solid var(--bd2);border-radius:8px;padding:14px}
.lvtop{display:flex;align-items:center;gap:14px;margin-bottom:12px}
.lvnum{width:78px;flex-shrink:0}
.lvnum input{font-family:var(--fh);font-size:24px;font-weight:700;color:var(--aq);text-align:center;padding:6px}
.lvinfo{flex:1;min-width:0}
.lvinfo .rk{font-family:var(--fh);font-size:11px;color:var(--gold);letter-spacing:1px;text-transform:uppercase}
.lvinfo .sp{font-family:var(--ft);font-size:12px;color:var(--t2);margin-top:3px}
.lvinfo .sp b{color:var(--aq);font-family:var(--fh)}
input[type=range]{width:100%;accent-color:var(--aq);cursor:pointer}
