.sl-wrap{margin-bottom:13px}
.sl-top{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:2px}
.sl-n{display:flex;align-items:center;gap:7px;font-family:var(--fh);font-size:11px;font-weight:600;color:var(--t1);letter-spacing:0.5px;text-transform:uppercase}
.sl-n svg{width:13px;height:13px;stroke:var(--aq);fill:none;stroke-width:1.6}
.sl-v{font-family:var(--fh);font-size:15px;font-weight:700;color:var(--aq)}.sl-v .of{font-size:9px;color:var(--t3)}
.sl-d{font-family:var(--ft);font-size:10px;font-style:italic;color:var(--t3);margin-bottom:6px}
.sl-bar{display:flex;gap:2px;height:18px}
.sl-tick{flex:1;background:var(--bg);border:1px solid var(--bd2);border-radius:2px;cursor:pointer;transition:.12s}
.sl-tick.on{background:var(--aq-dim);border-color:var(--aq-dim)}
.sl-tick.on.crit{background:var(--aq);border-color:var(--aq)}
.sl-tick:hover{border-color:var(--aq)}
/* SP budget */
.spbar{position:sticky;top:0;z-index:3;display:flex;align-items:center;gap:12px;background:var(--sec2);border:1px solid var(--gold-line);border-radius:8px;padding:11px 14px;margin-bottom:15px}
.spbar svg{width:22px;height:22px;stroke:var(--gold);fill:none;stroke-width:1.5;flex-shrink:0}
.spbar .spi{flex:1;min-width:0}
.spbar .sprem{font-family:var(--fh);font-size:20px;font-weight:700;color:var(--gold);line-height:1}
.spbar .sprem.neg{color:var(--red)}
.spbar .spsub{font-family:var(--ft);font-size:10px;color:var(--t2);margin-top:2px}
.spbar .sppool{width:74px;flex-shrink:0}
.spbar .sppool label{display:block;font-family:var(--fh);font-size:7.5px;letter-spacing:1px;color:var(--t3);text-transform:uppercase;margin-bottom:3px;text-align:center}
.spbar .sppool input{font-family:var(--fh);font-size:15px;font-weight:700;text-align:center;color:var(--gold);padding:5px}
/* list builder */
.lst-wrap{display:flex;flex-direction:column;gap:8px;margin-bottom:12px}
.lst-c{display:flex;gap:9px;align-items:flex-start;background:var(--sec);border:1px solid var(--bd);border-left:2px solid var(--aq);border-radius:6px;padding:9px 11px}
.lst-i{flex:1;min-width:0}
.lst-n{font-family:var(--fh);font-size:13px;font-weight:600;color:var(--t1)}
.lst-t{font-family:var(--fh);font-size:9px;color:var(--gold);letter-spacing:0.5px;text-transform:uppercase;margin-top:2px}
.lst-d{font-family:var(--ft);font-size:11px;color:var(--t2);line-height:1.45;margin-top:3px}
.lst-del{flex-shrink:0;width:24px;height:24px;border:1px solid var(--bd2);border-radius:5px;background:var(--card);color:var(--t3);cursor:pointer;display:flex;align-items:center;justify-content:center}
.lst-del:hover{color:var(--red);border-color:var(--red)}.lst-del svg{width:13px;height:13px;stroke:currentColor;fill:none}
.empty{font-family:var(--ft);font-style:italic;font-size:12px;color:var(--t3);text-align:center;padding:13px;border:1px dashed var(--bd2);border-radius:6px}
.addbtn{width:100%;font-family:var(--fh);font-size:10px;letter-spacing:1px;text-transform:uppercase;color:var(--aq);background:var(--aq-bg);border:1px dashed var(--aq-dim);border-radius:7px;padding:11px;cursor:pointer}
.addbtn:hover{background:var(--aq);color:var(--bg)}
/* popup */
.pop{position:fixed;inset:0;background:rgba(4,8,15,.74);display:none;align-items:center;justify-content:center;z-index:40;padding:18px}
.pop.vis{display:flex}
.pop-c{width:100%;max-width:380px;background:var(--card);border:1px solid var(--bd2);border-radius:12px;padding:18px;max-height:88vh;overflow-y:auto}
.pop-h{font-family:var(--fh);font-size:12px;font-weight:600;color:var(--aq);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:14px}
.pop-act{display:flex;gap:9px;margin-top:8px}
.pop-act button{flex:1;font-family:var(--fh);font-size:11px;letter-spacing:1px;text-transform:uppercase;border-radius:7px;padding:11px;cursor:pointer;border:1px solid var(--bd2)}
.pop-cancel{background:var(--sec);color:var(--t2)}
.pop-add{background:linear-gradient(180deg,var(--aq-hi),var(--aq));color:var(--bg);border-color:var(--aq)!important}
/* foot */
.foot{padding:16px 20px 20px;background:var(--sec);border-top:1px solid var(--bd);display:flex;flex-direction:column;gap:10px}
.donebtn{font-family:var(--fh);font-size:13px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--bg);background:linear-gradient(180deg,var(--aq-hi),var(--aq));border:none;border-radius:8px;padding:14px;cursor:pointer;box-shadow:0 6px 18px -4px var(--aq)}
.donebtn:hover{filter:brightness(1.08)}
.foot-note{font-family:var(--ft);font-size:10px;font-style:italic;color:var(--t3);text-align:center}
/* sending overlay */
.snd{position:fixed;inset:0;background:rgba(4,8,15,.92);display:none;flex-direction:column;align-items:center;justify-content:center;z-index:60;text-align:center;padding:24px}
.snd.on{display:flex}
.snd .ring{width:54px;height:54px;border:3px solid var(--bd2);border-top-color:var(--aq);border-radius:50%;animation:spin 0.8s linear infinite;margin-bottom:18px}
@keyframes spin{to{transform:rotate(360deg)}}
.snd .st{font-family:var(--fh);font-size:14px;color:var(--aq);letter-spacing:2px;text-transform:uppercase}
.snd .ss{font-family:var(--ft);font-size:12px;font-style:italic;color:var(--t2);margin-top:8px}
</style>
