<body>
<div class="app" id="app">
  <div class="top">
    <div class="top-meta"><span id="meta1">AXEL GUILD</span><span id="meta2">NEW SOUL</span></div>
    <div class="toolbar"><button class="tbtn" id="btnLn" onclick="KS.ln()">EN</button><button class="tbtn" onclick="KS.th()">◐</button></div>
    <h1 id="hHead">Adventurer Registration</h1>
    <div class="sub" id="sub">Fill the card freely — every field is yours to set.</div>
  </div>

  <div class="tabs">
    <div class="tab on" id="tb1" onclick="KS.tab(1)"><svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/></svg><span id="tb1l">Identity</span></div>
    <div class="tab" id="tb2" onclick="KS.tab(2)"><svg viewBox="0 0 24 24"><path d="M3 11l9-7 9 7"/><path d="M5 10v10h14V10"/></svg><span id="tb2l">Origin</span></div>
    <div class="tab" id="tb3" onclick="KS.tab(3)"><svg viewBox="0 0 24 24"><line x1="4" y1="21" x2="4" y2="13"/><line x1="4" y1="9" x2="4" y2="3"/><line x1="12" y1="21" x2="12" y2="12"/><line x1="20" y1="21" x2="20" y2="15"/><line x1="1" y1="13" x2="7" y2="13"/></svg><span id="tb3l">Class & Stats</span></div>
    <div class="tab" id="tb4" onclick="KS.tab(4)"><svg viewBox="0 0 24 24"><path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/></svg><span id="tb4l">Skills</span></div>
    <div class="tab" id="tb5" onclick="KS.tab(5)"><svg viewBox="0 0 24 24"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg><span id="tb5l">Path</span></div>
  </div>

  <!-- PAGE 1 IDENTITY -->
  <div class="page on" id="pg1">
    <div class="rec" id="r1">Record I — Identity</div>
    <div class="rec-d" id="r1d"></div>
    <div class="fld"><label class="lbl" id="lName">Full Name</label><input type="text" id="fName" placeholder="e.g. Satou Kazuma"/></div>
    <div class="fld"><label class="lbl" id="lClass">Class / Job</label>
      <div class="cusrow"><div><select id="fClassPre"></select><input type="text" id="fClassCus" style="display:none" placeholder="custom class"/></div><button class="cusbtn" id="btnClass" onclick="KS.tc('Class')">CUSTOM</button></div>
      <div class="hint" id="hClass"></div></div>
    <div class="row">
      <div class="fld"><label class="lbl" id="lAge">Age</label><input type="text" id="fAge" placeholder="17"/></div>
      <div class="fld"><label class="lbl" id="lGen">Gender</label><select id="fGen"></select></div>
      <div class="fld"><label class="lbl" id="lYear">Card No. / Year</label><input type="text" id="fYear" placeholder="0001"/></div>
    </div>
    <div class="fld"><label class="lbl" id="lApp">Appearance & Bearing</label><textarea id="fApp" placeholder="Hair, eyes, build, clothing, presence…"></textarea></div>
    <div class="fld"><label class="lbl" id="lMark">Distinguishing Mark</label><input type="text" id="fMark" placeholder="A scar, an eyepatch, a glow in the eyes…"/></div>
  </div>

  <!-- PAGE 2 ORIGIN -->
  <div class="page" id="pg2">
    <div class="rec" id="r2">Record II — Origin</div>
    <div class="rec-d" id="r2d"></div>
    <div class="fld"><label class="lbl" id="lRace">Race</label>
      <div class="cusrow"><div><select id="fRacePre"></select><input type="text" id="fRaceCus" style="display:none" placeholder="custom race"/></div><button class="cusbtn" id="btnRace" onclick="KS.tc('Race')">CUSTOM</button></div></div>
    <div class="fld"><label class="lbl" id="lOrigin">Origin</label><select id="fOrigin"></select></div>
    <div class="fld"><label class="lbl" id="lHome">Homeland</label>
      <div class="cusrow"><div><select id="fHomePre"></select><input type="text" id="fHomeCus" style="display:none" placeholder="custom homeland"/></div><button class="cusbtn" id="btnHome" onclick="KS.tc('Home')">CUSTOM</button></div></div>
    <div class="fld"><label class="lbl" id="lCheat">Blessing / Cheat</label>
      <div class="cusrow"><div><select id="fCheatPre"></select><input type="text" id="fCheatCus" style="display:none" placeholder="custom cheat / blessing"/></div><button class="cusbtn" id="btnCheat" onclick="KS.tc('Cheat')">CUSTOM</button></div>
      <div class="hint" id="hCheat"></div></div>
    <div class="fld"><label class="lbl" id="lBg">Background & Story</label><textarea id="fBg" placeholder="Who were you before? How long have you been in this world?"></textarea>
      <div class="hint" id="hBg"></div></div>
  </div>

  <!-- PAGE 3 CLASS & STATS -->
  <div class="page" id="pg3">
    <div class="rec" id="r3">Record III — Class, Level & Stats</div>
    <div class="rec-d" id="r3d"></div>
    <div class="fld"><label class="lbl" id="lLevel">Level</label>
      <div class="lvbox">
        <div class="lvtop">
          <div class="lvnum"><input type="number" id="fLevel" value="1" min="1" oninput="KS.lvlIn()"/></div>
          <div class="lvinfo"><div class="rk" id="lvRank">Rank: Beginner</div><div class="sp" id="lvSp"></div></div>
        </div>
        <input type="range" id="lvRange" min="1" max="60" value="1" oninput="KS.lvlSlide()"/>
        <div class="hint" id="hLevel"></div>
      </div></div>
    <div class="fld"><label class="lbl" id="hStat">Attributes</label><div class="rec-d" id="hStatD" style="margin-bottom:10px"></div>
      <div id="statBox"></div></div>
    <div class="fld"><label class="lbl">HP · MP · Eris</label>
      <div class="row">
        <div><input type="number" id="fHP" placeholder="HP" min="0"/></div>
        <div><input type="number" id="fMP" placeholder="MP" min="0"/></div>
      </div>
      <div class="row" style="margin-top:8px">
        <div><input type="number" id="fEris" placeholder="Eris" min="0"/></div>
        <div><input type="number" id="fDebt" placeholder="Debt" min="0"/></div>
      </div>
      <div class="hint" id="hVit"></div></div>
  </div>

  <!-- PAGE 4 SKILLS -->
  <div class="page" id="pg4">
    <div class="rec" id="r4">Record IV — Skills & Skill Points</div>
    <div class="rec-d" id="r4d"></div>
    <div class="spbar">
      <svg viewBox="0 0 24 24"><path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/></svg>
      <div class="spi"><div class="sprem" id="spRem">0</div><div class="spsub" id="spSub">spent 0 of 0 SP</div></div>
      <div class="sppool"><label id="lPool">SP Pool</label><input type="number" id="fPool" value="1" min="0" oninput="KS.poolTouch()"/></div>
    </div>
    <div class="lst-wrap" id="lSk"></div>
    <button class="addbtn" id="bSkAdd" onclick="KS.op('popSk')">Add a Skill</button>
  </div>

  <!-- PAGE 5 PATH -->
  <div class="page" id="pg5">
    <div class="rec" id="r5">Record V — Path, Party & Fate</div>
    <div class="rec-d" id="r5d"></div>
    <div class="fld"><label class="lbl" id="lFac">Affiliation / Faction</label>
      <div class="cusrow"><div><select id="fFacPre"></select><input type="text" id="fFacCus" style="display:none" placeholder="custom faction"/></div><button class="cusbtn" id="btnFac" onclick="KS.tc('Fac')">CUSTOM</button></div></div>
    <div class="fld"><label class="lbl" id="lRep">Reputation</label><select id="fRep"></select></div>
    <div class="fld"><label class="lbl" id="lGoal">Goal / Driving Wish</label><input type="text" id="fGoal" placeholder="Defeat the Demon King? Just live comfortably?"/></div>
    <div class="row">
      <div class="fld"><label class="lbl" id="lPub">Public Persona</label><textarea id="fPub" placeholder="How you appear to others"></textarea></div>
      <div class="fld"><label class="lbl" id="lPriv">Private Truth</label><textarea id="fPriv" placeholder="What you hide"></textarea></div>
    </div>
    <div class="fld"><label class="lbl">Party</label>
      <div class="lst-wrap" id="lParty"></div>
      <button class="addbtn" id="bPartyAdd" onclick="KS.op('popParty')">Add a Companion</button></div>
    <div class="fld"><label class="lbl" id="lScn">Opening Scene</label>
      <div class="cusrow"><div><select id="fScnPre"></select><input type="text" id="fScnCus" style="display:none" placeholder="custom opening scene"/></div><button class="cusbtn" id="btnScn" onclick="KS.tc('Scn')">CUSTOM</button></div>
      <div class="hint" id="hScn"></div></div>
  </div>

  <div class="foot">
    <button class="donebtn" id="bDone" onclick="KS.send()">Register at the Guild</button>
    <div class="foot-note" id="footNote"></div>
  </div>
</div>

<!-- POPUP: SKILL -->
<div class="pop" id="popSk">
  <div class="pop-c">
    <div class="pop-h" id="popSkH">Add a Skill / Spell</div>
    <div class="fld"><label class="lbl" id="lSkP">Skill / Spell</label><select id="iSkP" onchange="KS.skPick()"></select></div>
    <div class="fld"><label class="lbl" id="lSkN">Custom name (overrides)</label><input type="text" id="iSkN" placeholder="optional custom name"/></div>
    <div class="row">
      <div class="fld"><label class="lbl" id="lSkCost">SP cost</label><input type="number" id="iSkCost" placeholder="0" min="0"/></div>
      <div class="fld"><label class="lbl">Category</label><input type="text" id="iSkCat" placeholder="category"/></div>
    </div>
    <div class="fld"><label class="lbl" id="lSkD">Notes</label><input type="text" id="iSkD" placeholder="what it does (optional)"/></div>
    <div class="pop-act"><button class="pop-cancel" id="cSkC" onclick="KS.cp('popSk')">Cancel</button><button class="pop-add" id="cSkA" onclick="KS.addSk()">Add</button></div>
  </div>
</div>

<!-- POPUP: PARTY -->
<div class="pop" id="popParty">
