  function g(id){return document.getElementById(id);}
  function cVal(id){var e=g(id);return e?(e.value||'').trim():'';}
  function nval(id,def){var n=parseInt(cVal(id),10);return isNaN(n)?def:n;}

  function fill(id,arr){
    var sel=g(id); if(!sel)return; var cur=sel.value; var th=(S.ln==='th'); var html='';var open=false;
    arr.forEach(function(o){
      if(o[3]==='grp'){ if(open)html+='</optgroup>'; html+='<optgroup label="'+(th?o[2]:o[1])+'">';open=true;return;}
      if(o[3]==='grp_no'){ if(open){html+='</optgroup>';open=false;} html+='<option value="">'+(th?o[2]:o[1])+'</option>';return;}
      html+='<option value="'+o[0]+'">'+(th?o[2]:o[1])+'</option>';
    });
    if(open)html+='</optgroup>'; sel.innerHTML=html; sel.value=cur;
  }
  function fillAll(){
    fill('fClassPre',D.klass);fill('fGen',D.gen);fill('fRacePre',D.race);fill('fOrigin',D.origin);
    fill('fHomePre',D.home);fill('fCheatPre',D.cheat);fill('fFacPre',D.fac);fill('fRep',D.rep);
    fill('iSkP',CAT);fill('iPartyP',D.party);fill('fScnPre',D.scn);
  }
  function updCus(K){
    var flag=S['c'+K]; var btn=g('btn'+K),sel=g('f'+K+'Pre'),inp=g('f'+K+'Cus');
    if(btn) btn.textContent= flag?(S.ln==='th'?'พรีเซ็ต':'PRESET'):(S.ln==='th'?'เอง':'CUSTOM');
    if(sel) sel.style.display=flag?'none':'block';
    if(inp) inp.style.display=flag?'block':'none';
  }
  function tVal(K){ return S['c'+K]?cVal('f'+K+'Cus'):cVal('f'+K+'Pre'); }

  function rankFor(lv){ var th=(S.ln==='th'); return lv>30?(th?'ขั้นสูง':'Advanced'):(lv>=20?(th?'ขั้นกลาง':'Intermediate'):(th?'มือใหม่':'Beginner')); }
  function suggestPool(lv){ return lv; } // ~1 SP per level (born-with + level-ups), freely editable

  function syncLvl(){
    var th=(S.ln==='th');
    g('lvRank').textContent=(th?'อันดับ: ':'Rank: ')+rankFor(S.lvl);
    g('lvSp').innerHTML=(th?'แนะนำพ้อยสกิลเริ่มต้น: ':'Suggested starting SP: ')+'<b>'+suggestPool(S.lvl)+'</b>';
    g('lvRange').value=Math.min(60,S.lvl);
  }

  function bSt(){
    var b=g('statBox'); if(!b)return; b.innerHTML=''; var th=(S.ln==='th');
    var ICA={str:'<path d="M6 13a4 4 0 1 1 4-4"/><path d="M14 11a4 4 0 1 0 4 4"/><line x1="9" y1="9" x2="15" y2="15"/>',vit:'<path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/>',agi:'<path d="M13 2L4.5 13.5H11l-1 8.5L19.5 10H13z"/>',dex:'<circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/>',int:'<path d="M9 18h6"/><path d="M12 2a7 7 0 0 0-4 12.7V17h8v-2.3A7 7 0 0 0 12 2z"/>',mgc:'<path d="M12 3C9 8 6 11 6 15a6 6 0 0 0 12 0c0-4-3-7-6-12z"/>',luk:'<path d="M12 21c-1-5-5-6-5-10a5 5 0 0 1 10 0c0 4-4 5-5 10z"/>'};
    STATS.forEach(function(s){
      var cur=S.stats[s[0]]||5;
      var w=document.createElement('div'); w.className='sl-wrap';
      w.innerHTML='<div class="sl-top"><div class="sl-n"><svg viewBox="0 0 24 24" fill="none">'+ICA[s[0]]+'</svg>'+(th?s[3]:s[1])+'</div><div class="sl-v"><span id="sv_'+s[0]+'">'+cur+'</span><span class="of">/10</span></div></div><div class="sl-d">'+(th?s[5]:s[4])+'</div>';
      var bar=document.createElement('div'); bar.className='sl-bar';
      for(var i=1;i<=10;i++){
        var tk=document.createElement('div'); tk.className='sl-tick'; tk.dataset.v=i;
        if(i<=cur)tk.classList.add('on'); if(i>=9&&i<=cur)tk.classList.add('crit');
        (function(val,key,wrap){ tk.addEventListener('click',function(){
          S.stats[key]=val; var vv=g('sv_'+key); if(vv)vv.textContent=val;
          wrap.querySelectorAll('.sl-tick').forEach(function(tt){var n=parseInt(tt.dataset.v,10);tt.classList.toggle('on',n<=val);tt.classList.toggle('crit',n>=9&&n<=val);});
        });})(i,s[0],bar);
        bar.appendChild(tk);
      }
      w.appendChild(bar); b.appendChild(w);
    });
  }

  function spent(){ var t=0; S.sk.forEach(function(s){t+=parseInt(s.cost,10)||0;}); return t; }
  function updSP(){
    var pool=nval('fPool',S.lvl); S.pool=pool;
    var rem=pool-spent(); var el=g('spRem'); if(el){ el.textContent=rem; el.classList.toggle('neg',rem<0); }
    var sub=g('spSub'); if(sub){ var th=(S.ln==='th'); sub.textContent=(th?'ใช้ไป '+spent()+' จาก '+pool+' พ้อย':'spent '+spent()+' of '+pool+' SP'); }
  }

  var XSVG='<svg viewBox="0 0 24 24" stroke-width="2" stroke-linecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>';
  function rSk(){
    var wrap=g('lSk'); if(!wrap)return; wrap.innerHTML=''; var th=(S.ln==='th');
    if(!S.sk.length){ wrap.innerHTML='<div class="empty">'+(th?'ยังไม่ได้เลือกสกิล':'No skills chosen yet')+'</div>'; updSP(); return; }
    S.sk.forEach(function(item,idx){
      var c=document.createElement('div'); c.className='lst-c';
      c.innerHTML='<div class="lst-i"><div class="lst-n">'+esc(item.n)+'</div><div class="lst-t">'+esc(item.cat)+' · '+item.cost+' SP</div>'+(item.d?'<div class="lst-d">'+esc(item.d)+'</div>':'')+'</div>';
      var b=document.createElement('button'); b.className='lst-del'; b.innerHTML=XSVG;
      b.onclick=function(){ S.sk.splice(idx,1); rSk(); };
      c.appendChild(b); wrap.appendChild(c);
    });
